import React, { useState, useEffect, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  ShoppingBag, 
  Menu, 
  X, 
  Sun, 
  Moon,
  Smartphone,
  Monitor,
  RefreshCw,
  Maximize2,
  Minimize2
} from 'lucide-react';
import { Theme, CartItem, Product } from './types';
import LandingPage from './pages/LandingPage';
import ShopPage from './pages/ShopPage';
import CustomizerPage from './pages/CustomizerPage';
import CartPage from './pages/CartPage';
import CommunityPage from './pages/CommunityPage';

// Context for Cart and Theme
interface AppContextType {
  theme: Theme;
  setTheme: (t: Theme) => void;
  cart: CartItem[];
  addToCart: (p: Product, custom?: any) => void;
  removeFromCart: (id: string) => void;
  toggleCart: () => void;
  isCartOpen: boolean;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>(() => {
    try {
      const savedTheme = window.localStorage.getItem('tribe-designs-theme');
      if (savedTheme && (savedTheme === Theme.LIGHT || savedTheme === Theme.DARK)) {
        return savedTheme as Theme;
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? Theme.DARK : Theme.LIGHT;
    } catch {
      return Theme.DARK;
    }
  });

  const [cart, setCart] = useState<CartItem[]>(() => {
    try {
      const savedCart = window.localStorage.getItem('tribe-designs-cart');
      return savedCart ? JSON.parse(savedCart) : [];
    } catch (error) {
      console.error("Failed to load cart from localStorage:", error);
      return [];
    }
  });

  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileView, setIsMobileView] = useState(false);

  useEffect(() => {
    if (theme === Theme.DARK) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    try {
      window.localStorage.setItem('tribe-designs-theme', theme);
    } catch (error) {
      console.error("Failed to save theme to localStorage:", error);
    }
  }, [theme]);

  useEffect(() => {
    try {
      window.localStorage.setItem('tribe-designs-cart', JSON.stringify(cart));
    } catch (error) {
      console.error("Failed to save cart to localStorage:", error);
    }
  }, [cart]);


  const addToCart = (product: Product, customization?: any) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id && JSON.stringify(item.customization) === JSON.stringify(customization));
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, customization, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const toggleCart = () => setIsCartOpen(!isCartOpen);

  return (
    <AppContext.Provider value={{ theme, setTheme, cart, addToCart, removeFromCart, toggleCart, isCartOpen }}>
      <HashRouter>
        <div className={`min-h-screen bg-white dark:bg-zinc-950 text-zinc-900 dark:text-zinc-50 selection:bg-amber-400 selection:text-black transition-all duration-500 ${
          isMobileView ? 'max-w-[400px] mx-auto shadow-2xl border-x border-zinc-200 dark:border-zinc-800' : ''
        }`}>
          <Navbar isMobileView={isMobileView} />
          <main className="pt-20">
            <Routes>
              <Route path="/" element={<LandingPage />} />
              <Route path="/shop" element={<ShopPage />} />
              <Route path="/customize" element={<CustomizerPage />} />
              <Route path="/cart" element={<CartPage />} />
              <Route path="/community" element={<CommunityPage />} />
            </Routes>
          </main>
          <Footer />
          <CartSidebar />

          <ViewControls 
            isMobileView={isMobileView} 
            setIsMobileView={setIsMobileView} 
          />
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

const ViewControls: React.FC<{ isMobileView: boolean; setIsMobileView: (v: boolean) => void }> = ({ isMobileView, setIsMobileView }) => {
  const [isFullscreen, setIsFullscreen] = useState(false);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const reloadApp = () => {
    window.location.reload();
  };

  return (
    <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 z-[100] flex items-center gap-1 p-1.5 bg-black/80 dark:bg-white/90 backdrop-blur-xl rounded-full shadow-2xl border border-white/10 dark:border-black/10 transition-all hover:scale-105">
      <button 
        onClick={() => setIsMobileView(false)}
        className={`p-3 rounded-full transition-all ${!isMobileView ? 'bg-amber-500 text-black shadow-lg' : 'text-zinc-400 hover:text-white dark:hover:text-black'}`}
        title="Desktop View"
      >
        <Monitor size={18} />
      </button>
      <button 
        onClick={() => setIsMobileView(true)}
        className={`p-3 rounded-full transition-all ${isMobileView ? 'bg-amber-500 text-black shadow-lg' : 'text-zinc-400 hover:text-white dark:hover:text-black'}`}
        title="Mobile View"
      >
        <Smartphone size={18} />
      </button>

      <div className="w-px h-6 bg-zinc-700 dark:bg-zinc-300 mx-1 opacity-50"></div>

      <button 
        onClick={reloadApp}
        className="p-3 rounded-full text-zinc-400 hover:text-white dark:hover:text-black hover:bg-white/10 dark:hover:bg-black/10 transition-all"
        title="Reload App"
      >
        <RefreshCw size={18} />
      </button>
      <button 
        onClick={toggleFullscreen}
        className="p-3 rounded-full text-zinc-400 hover:text-white dark:hover:text-black hover:bg-white/10 dark:hover:bg-black/10 transition-all"
        title="Toggle Fullscreen"
      >
        {isFullscreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
      </button>
    </div>
  );
};

