      return savedUser ? JSON.parse(savedUser) : defaultUser;
    } catch {
      return defaultUser;
    }
  });

  const [isCommunityMember, setIsCommunityMember] = useState<boolean>(() => {
    try {
        return window.localStorage.getItem('tribe-designs-member') === 'true';
