                                      <CheckCircle size={14} />
                                  </div>
                                  <span className="text-[10px] font-bold uppercase">Delivered</span>
                              </div>
                          </div>
                      </div>
                  </div>
              ))
          )}
      </div>
  );

  if (checkoutStep === 'success') {
