  address: {
    street: string;
    city: string;
    state: string;
    zip: string;
    country: string;
  };
}

export interface Order {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  status: 'Processing' | 'Shipped' | 'Out for Delivery' | 'Delivered';
  paymentMethod: 'card' | 'momo' | 'crypto' | 'cod';
  shippingDetails: {
    name: string;
    address: string;
    city: string;
  };
}

