                        <input value={number} onChange={(e) => setNumber(e.target.value)} maxLength={2} className="w-full bg-zinc-100 dark:bg-zinc-900 p-4 rounded-xl font-bold uppercase text-center outline-none focus:ring-2 focus:ring-amber-500" />
