                           {COLORS.map(c => (
                               <button key={c.hex} onClick={() => setSleeveColor(c.hex)} className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 ${sleeveColor === c.hex ? 'border-amber-500 ring-2 ring-amber-500 ring-offset-2' : 'border-transparent'}`} style={{ backgroundColor: c.hex }} title={c.name} />
