                             <button onClick={() => setShowPattern(!showPattern)} className={`text-[10px] font-black px-2 py-0.5 rounded transition-colors ${showPattern ? 'bg-amber-500 text-black' : 'bg-zinc-200 text-zinc-400'}`}>
                                 {showPattern ? 'ENABLED' : 'DISABLED'}
