                          <input value={name} onChange={(e) => setName(e.target.value)} maxLength={12} className="w-full bg-zinc-100 dark:bg-zinc-900 p-4 rounded-xl font-bold uppercase outline-none focus:ring-2 focus:ring-amber-500 transition-all" />
                      </div>
                      <div className="space-y-2">
                          <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 block">Jersey Number</label>
                          <input value={number} onChange={(e) => setNumber(e.target.value)} maxLength={2} className="w-full bg-zinc-100 dark:bg-zinc-900 p-4 rounded-xl font-bold uppercase text-center outline-none focus:ring-2 focus:ring-amber-500 transition-all" />
                      </div>
                </div>
                <div>
                   <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 mb-3 block">Typography Style</label>
                   <div className="flex gap-2">
                      {ATHLETIC_FONTS.map(f => (
                        <button key={f.id} onClick={() => setAthleticFont(f)} className={`flex-1 py-3 border-2 rounded-xl text-xs font-bold uppercase ${athleticFont.id === f.id ? 'border-amber-500 bg-amber-500/10' : 'border-zinc-200'}`} style={{ fontFamily: f.family }}>
                          {f.name}
                        </button>
                      ))}
                   </div>
                </div>
              </div>
           ) : (
              <div className="space-y-6">
                 <div className="flex items-center gap-2 mb-2">
                    <Type size={18} className="text-amber-500" />
                    <h3 className="text-xs font-black uppercase tracking-widest">Print Details</h3>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 mb-2 block">Street Text</label>
                        <input value={printText} onChange={(e) => setPrintText(e.target.value)} className="w-full bg-zinc-100 dark:bg-zinc-900 p-4 rounded-xl font-bold uppercase outline-none focus:ring-2 focus:ring-amber-500" placeholder="STREET VIBE" />
                    </div>
                    <div className="relative">
                        <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 mb-2 block">Graphic Overlay</label>
                        <div className="border-2 border-dashed border-zinc-200 dark:border-zinc-800 rounded-2xl p-6 text-center hover:border-amber-500 transition-colors relative cursor-pointer">
                           <Upload size={24} className="mx-auto mb-2 text-zinc-400" />
                           <span className="text-xs font-bold text-zinc-500 uppercase">Upload PNG/JPG</span>
                           <input type="file" accept="image/*" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                        </div>
                    </div>
                </div>
              </div>
           )}

           {/* SIZE & ACTIONS */}
           <div className="pt-6 border-t border-zinc-200 dark:border-zinc-800 space-y-8">
                <div>
                    <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 mb-4 block flex items-center gap-2">
                        <Ruler size={14} /> Global Sizing
                    </label>
                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                        {SIZES.map((size) => (
                            <button key={size} onClick={() => setSelectedSize(size)} className={`min-w-[3.5rem] py-3 rounded-xl border-2 transition-all font-black text-xs ${selectedSize === size ? 'border-amber-500 bg-amber-500 text-black' : 'border-zinc-200 text-zinc-500 hover:border-zinc-400'}`}>
                                {size}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-3">
                    <button onClick={handleSave} className="w-full bg-amber-500 hover:bg-amber-600 text-black py-5 rounded-2xl font-syne font-black text-lg tracking-widest transition-all shadow-xl active:scale-95 flex items-center justify-center gap-3">
                        <Save size={20} />
                        ADD TO BAG - $120
                    </button>
                    <button 
                      onClick={() => { setDraftSaved(true); setTimeout(() => setDraftSaved(false), 2000); }} 
                      className={`w-full py-4 rounded-xl font-black uppercase tracking-widest text-xs border-2 transition-all flex items-center justify-center gap-2 ${draftSaved ? 'bg-green-500 border-green-500 text-white' : 'border-zinc-200 text-zinc-500 hover:border-black'}`}
                    >
                      {draftSaved ? <><Check size={16} /> Saved to Tribe</> : <><RefreshCcw size={16} /> Reset Design</>}
                    </button>
                    <p className="text-[10px] text-zinc-400 text-center font-bold uppercase tracking-widest">Handcrafted in 5-7 business days in our Nairobi studio.</p>
                </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default CustomizerPage;

export interface Product {
  id: string;
  name: string;
  price: number;
  image: string;
  category: 'Modern' | 'Heritage';
  subcategory: 'jerseys' | 'hoodies' | 't-shirts';
  description: string;
  customizable?: boolean;
  gender?: 'male' | 'female' | 'unisex';
}

export interface CustomizationOptions {
  mode: 'athletic' | 'printout';
  name?: string;
  number?: string;
  layout?: 'name-top' | 'number-top';
  kit?: 'dark' | 'light';
  // Granular Colors
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  collarColor?: string;
  patternColor?: string;
  showPattern?: boolean;

  uploadedImage?: string;
  printText?: string;
  printFont?: string;
  placement?: 'front' | 'back';
  size?: string;
}

export interface CartItem extends Product {
  customization?: CustomizationOptions;
  quantity: number;
}

export interface UserProfile {
  name: string;
  email: string;
  phone: string;
  avatar?: string; // Base64 string for profile picture
  address: {
    street: string;
    city: string;
    state: string;
    zip: string;
    country: string;
  };
}

export interface Order {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  status: 'Processing' | 'Shipped' | 'Out for Delivery' | 'Delivered';
  paymentMethod: 'card' | 'momo' | 'crypto' | 'cod';
  shippingDetails: {
    name: string;
    address: string;
    city: string;
  };
}

export enum Theme {
  LIGHT = 'light',
  DARK = 'dark'
}

import React, { useState } from 'react';
import { JERSEYS } from '../constants';
import { useApp } from '../App';
import { ShoppingCart, Edit3 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { Product } from '../types';

const ShopPage: React.FC = () => {
  const { addToCart } = useApp();
  const navigate = useNavigate();
  const [activeCategory, setActiveCategory] = useState<'Heritage' | 'Modern'>('Heritage');
  const [activeSubCategory, setActiveSubCategory] = useState<string>('all');

  // Define subcategories for tabs based on user requirements
  const subCategories = activeCategory === 'Heritage' 
    ? ['all', 'jerseys']
    : ['all', 'hoodies', 't-shirts'];

  // Filter items
  const filtered = JERSEYS.filter(j => {
      const catMatch = j.category === activeCategory;
      const subMatch = activeSubCategory === 'all' || j.subcategory === activeSubCategory;
      return catMatch && subMatch;
  });

  const handleProductAction = (product: Product) => {
      if (product.customizable) {
          // Determine mode based on subcategory
          const mode = product.subcategory === 'jerseys' ? 'athletic' : 'printout';
          navigate('/customize', { state: { mode, preselectedItem: product.name } });
      } else {
          addToCart(product);
      }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 md:py-12">
      <div className="flex flex-col gap-6 mb-12">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
            <div>
            <h1 className="text-4xl md:text-7xl font-syne font-black tracking-tighter uppercase mb-2 md:mb-4">THE SHOP</h1>
            <p className="text-sm md:text-base text-zinc-500 max-w-md font-medium">Limited release items. Authentic African Heritage Jerseys & Modern Streetwear.</p>
            </div>

            <div className="flex bg-zinc-100 dark:bg-zinc-900 p-1.5 rounded-2xl w-full md:w-auto">
            {['Heritage', 'Modern'].map((cat) => (
                <button
                key={cat}
                onClick={() => {
                    setActiveCategory(cat as any);
                    setActiveSubCategory('all');
                }}
                className={`flex-1 md:flex-none px-8 py-3 rounded-xl text-sm font-black tracking-widest uppercase transition-all ${
                    activeCategory === cat 
                    ? 'bg-black dark:bg-white text-white dark:text-black shadow-lg' 
                    : 'text-zinc-400 hover:text-black dark:hover:text-white'
                }`}
                >
                {cat.toUpperCase()}
                </button>
            ))}
            </div>
        </div>

        {/* Subcategory Tabs */}
        <div className="flex flex-wrap gap-2 pb-4 border-b border-zinc-200 dark:border-zinc-800 overflow-x-auto scrollbar-hide">
            {subCategories.map((sub) => (
                <button
                    key={sub}
                    onClick={() => setActiveSubCategory(sub)}
                    className={`px-4 py-2 rounded-full border border-zinc-200 dark:border-zinc-800 text-[10px] md:text-xs font-bold uppercase whitespace-nowrap transition-colors ${
                        activeSubCategory === sub
                        ? 'bg-amber-500 border-amber-500 text-black'
                        : 'bg-white dark:bg-zinc-900 text-zinc-500 hover:border-zinc-400'
                    }`}
                >
                    {sub === 'all' ? 'VIEW ALL' : sub.replace('-', ' ')}
                </button>
            ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-6 gap-y-10 md:gap-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
        {filtered.map((product) => (
          <div key={product.id} className="group relative">
            <div className="aspect-[3/4] overflow-hidden rounded-2xl bg-zinc-100 dark:bg-zinc-900 relative">
              <img 
                src={product.image} 
                alt={product.name}
                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
              />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-4">
                <button 
                  onClick={() => handleProductAction(product)}
                  className={`px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs flex items-center gap-2 shadow-xl transform scale-0 group-hover:scale-100 duration-300 ${
                    product.customizable 
                    ? 'bg-white text-black hover:bg-amber-500' 
                    : 'bg-amber-500 text-black hover:bg-white'
                  }`}
                >
                   {product.customizable ? (
                       <> <Edit3 size={16} /> Customize </>
                   ) : (
                       <> <ShoppingCart size={16} /> Add to Bag </>
                   )}
                </button>
              </div>
              <div className="absolute top-4 left-4 flex gap-2">
                <span className="bg-black/80 backdrop-blur px-3 py-1 rounded-full text-[10px] font-black tracking-widest text-white uppercase border border-white/20">
                  {product.subcategory}
                </span>
                {product.gender && (
                    <span className="bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[10px] font-black tracking-widest text-black uppercase">
                        {product.gender}
                    </span>
                )}
              </div>
            </div>

            <div className="mt-4 md:mt-6 flex justify-between items-start">
              <div className="flex-1 pr-4">
                <h3 className="font-syne font-bold text-lg md:text-xl uppercase tracking-tighter leading-tight">{product.name}</h3>
                <p className="text-zinc-500 text-xs md:text-sm mt-1 line-clamp-2">{product.description}</p>
                {product.customizable && (
                    <span className="inline-block mt-2 text-[10px] font-black bg-green-100 text-green-700 px-2 py-0.5 rounded border border-green-200 uppercase">
                        Customizable
                    </span>
                )}
              </div>
              <span className="font-syne font-black text-xl md:text-2xl text-amber-500">${product.price}</span>
            </div>
          </div>
        ))}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-20 opacity-50">
          <p className="text-xl md:text-2xl font-bold">NO ITEMS FOUND IN THIS COLLECTION</p>
        </div>
      )}
    </div>
  );
};

export default ShopPage;

import React, { useState, useEffect } from 'react';
import { PRINTOUT_COLORS, SIZE_CHART } from '../constants';
import { useApp } from '../App';
import { Save, Check, Ruler, Upload, Palette, Type, RefreshCcw, Eye } from 'lucide-react';
import { useLocation } from 'react-router-dom';
import { Product } from '../types';

const ATHLETIC_FONTS = [
  { id: 'college', name: 'VARSITY', family: "'Space Grotesk', sans-serif", letterSpacing: '0.05em' },
  { id: 'impact', name: 'IMPACT', family: "'Syne', sans-serif", letterSpacing: '0.1em' },
];

const COLORS = [
  { name: 'Pitch Black', hex: '#121212' },
  { name: 'Pure White', hex: '#ffffff' },
  { name: 'Amber Gold', hex: '#fbbf24' },
  { name: 'Heritage Green', hex: '#1DB954' },
  { name: 'Royal Blue', hex: '#2563eb' },
  { name: 'Fire Red', hex: '#dc2626' },
  { name: 'Sunset Orange', hex: '#ea580c' },
  { name: 'Desert Sand', hex: '#d4d4d8' },
];

const SIZES = Object.keys(SIZE_CHART) as Array<keyof typeof SIZE_CHART>;

const CustomizerPage: React.FC = () => {
  const { addToCart } = useApp();
  const location = useLocation();

  const [mode, setMode] = useState<'athletic' | 'printout'>('athletic');
  const [viewSide, setViewSide] = useState<'front' | 'back'>('front');

  // ATHLETIC COLORS
  const [torsoColor, setTorsoColor] = useState('#121212');
  const [sleeveColor, setSleeveColor] = useState('#121212');
  const [collarColor, setCollarColor] = useState('#fbbf24');
  const [accentColor, setAccentColor] = useState('#1DB954');
  const [patternColor, setPatternColor] = useState('#ffffff');
  const [showPattern, setShowPattern] = useState(true);

  // TEXT/NUMBER
  const [name, setName] = useState('YOUR NAME');
  const [number, setNumber] = useState('54');
  const [athleticFont, setAthleticFont] = useState(ATHLETIC_FONTS[0]);

  // PRINTOUT STATE
  const [printText, setPrintText] = useState('STREET VIBE');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // SHARED
  const [selectedSize, setSelectedSize] = useState('L');
  const [draftSaved, setDraftSaved] = useState(false);

  useEffect(() => {
    if (location.state && location.state.mode) {
      setMode(location.state.mode);
    }
  }, [location]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    const customProduct: Product = {
      id: `custom-${Date.now()}`,
      name: mode === 'athletic' ? `PRO ATHLETIC KIT` : `CUSTOM STREET PRINT`,
      price: mode === 'athletic' ? 120 : 65,
      image: 'https://images.unsplash.com/photo-1540331547168-8b63109225b7?auto=format&fit=crop&q=80&w=800',
      category: 'Modern',
      subcategory: mode === 'athletic' ? 'jerseys' : 't-shirts',
      description: `Custom ${mode} design. Size ${selectedSize}.`
    };

    addToCart(customProduct, {
      mode,
      name,
      number,
      primaryColor: torsoColor,
      secondaryColor: sleeveColor,
      accentColor: accentColor,
      collarColor: collarColor,
      patternColor: patternColor,
      showPattern,
      uploadedImage,
      printText,
      size: selectedSize
    });
  };

  const TribalPattern = () => (
    <svg className="absolute inset-0 w-full h-full opacity-10 pointer-events-none" xmlns="http://www.w3.org/2000/svg">
      <pattern id="tribal" x="0" y="0" width="100" height="100" patternUnits="userSpaceOnUse">
        <path d="M50 0 L100 50 L50 100 L0 50 Z" fill="none" stroke={patternColor} strokeWidth="0.5" />
        <path d="M0 0 L20 20 M80 80 L100 100 M100 0 L80 20 M20 80 L0 100" stroke={patternColor} strokeWidth="1" />
        <circle cx="50" cy="50" r="10" fill="none" stroke={patternColor} strokeWidth="0.5" />
      </pattern>
      <rect width="100%" height="100%" fill="url(#tribal)" />
    </svg>
  );

  const ShieldLogo = ({ className }: { className?: string }) => (
    <div className={`${className} flex flex-col items-center border-2 border-[${collarColor}] p-1 rounded-t-sm rounded-b-xl relative`} style={{ borderColor: collarColor }}>
      <span className="text-[5px] font-bold uppercase" style={{ color: collarColor }}>Tribe Designs</span>
      <span className="text-xs font-bold" style={{ color: collarColor }}>54</span>
      <div className="flex gap-0.5 mt-0.5">
        {[1, 2, 3].map(i => <div key={i} className="w-0.5 h-0.5 rounded-full" style={{ backgroundColor: collarColor }} />)}
      </div>
    </div>
  );

  const PanAfricaLogo = ({ className }: { className?: string }) => (
    <div className={`${className} flex flex-col items-center justify-center border-2 rounded-full p-1 bg-black/20`} style={{ borderColor: collarColor }}>
      <svg viewBox="0 0 100 100" className="w-12 h-12">
        <path d="M30,40 Q40,20 60,30 T70,60 T40,80 T20,60 Z" fill={collarColor} />
        <circle cx="50" cy="50" r="45" fill="none" stroke={collarColor} strokeWidth="2" strokeDasharray="2 2" />
      </svg>
      <span className="text-[6px] font-bold uppercase tracking-tighter text-center" style={{ color: collarColor }}>Pan Africa<br/>Leagues</span>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 md:py-16">
      {/* Mode Switcher */}
      <div className="flex flex-col md:flex-row justify-center items-center gap-4 mb-12">
        <div className="bg-zinc-100 dark:bg-zinc-900 p-1.5 rounded-2xl flex gap-1 shadow-inner">
          <button 
            onClick={() => setMode('athletic')}
            className={`px-8 py-3 rounded-xl font-black uppercase tracking-widest text-xs transition-all ${
              mode === 'athletic' 
              ? 'bg-black text-white dark:bg-white dark:text-black shadow-lg' 
              : 'text-zinc-400 hover:text-black dark:hover:text-white'
            }`}
          >
            Pro Athletic
          </button>
          <button 
             onClick={() => setMode('printout')}
             className={`px-8 py-3 rounded-xl font-black uppercase tracking-widest text-xs transition-all ${
              mode === 'printout' 
              ? 'bg-black text-white dark:bg-white dark:text-black shadow-lg' 
              : 'text-zinc-400 hover:text-black dark:hover:text-white'
            }`}
          >
            Street Print
          </button>
        </div>

        <div className="bg-zinc-100 dark:bg-zinc-900 p-1.5 rounded-2xl flex gap-1 shadow-inner">
          <button 
            onClick={() => setViewSide('front')}
            className={`px-6 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all flex items-center gap-2 ${
