           {/* SIZE & ACTIONS */}
           <div className="pt-6 border-t border-zinc-200 dark:border-zinc-800 space-y-8">
                <div>
                    <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 mb-4 block flex items-center gap-2">
