          <div key={product.id} className="group cursor-pointer" onClick={() => handleProductAction(product)}>
            <div className="aspect-[4/5] overflow-hidden rounded-[3rem] bg-zinc-100 dark:bg-zinc-900 relative shadow-2xl border-4 border-transparent group-hover:border-amber-500 transition-all duration-500">
